/*===================================================================================================================================*/
/*  U1    u1_g_oXDoCANDtcTrchk_B1500(const U2 u2_a_ELPSD)                                                                            */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      void                                                                                                             */
/*  Return:         OXDC_DTC_TR_INA  (0x00U)  : DTC Inactive                                                                         */
/*                  OXDC_DTC_TR_ACT  (0x01U)  : DTC Active                                                                           */
/*                  OXDC_DTC_TR_UNK  (0x02U)  : DTC Not Applicable                                                                   */
/*===================================================================================================================================*/
U1    u1_g_oXDoCANDtcTrchk_B1500(const U2 u2_a_ELPSD)
{
    U1           u1_t_sup_ch;
    U1           u1_t_tr_chk;

    u1_t_sup_ch = u1_g_TyDoCANXidSup_Fuel((U1)TYDC_FUEL_CH_MA);
    if(u1_t_sup_ch != (U1)TRUE){
        u1_t_tr_chk = (U1)OXDC_DTC_TR_N_A;
    }
    else{
        u1_t_tr_chk = u1_g_TyDoCANTrchkFuel((U1)TYDC_FUEL_CH_MA);
    }
    
    return(u1_t_tr_chk);
}
